sql:
SELECT state_name
FROM states
ORDER BY total_cases DESC;

SELECT district_name, total_active
FROM districts
ORDER BY total_active DESC;

SELECT district_name
FROM districts
WHERE vaccination_rate = (SELECT MAX(vaccination_rate) FROM districts);

SELECT total_active AS total_active_cases
FROM states
WHERE state_id = 1;

SELECT SUM(quantity) AS total_hospital_beds
FROM health_resources
WHERE district_id = 4;
